UPDATE `04_lista_status` SET ordem = ordem + 1 WHERE ordem >= 7;

-- Insert Teste at order 7
INSERT INTO `04_lista_status` (status, ordem, cor, ativo) VALUES ('Teste', 7, '#F97316', 1);

-- Now Pronto is at 8, Aguardando Retirada at 9, Entregue at 10
-- Add Agendado at 11 and Cancelado at 12
INSERT INTO `04_lista_status` (status, ordem, cor, ativo) VALUES ('Agendado', 11, '#6366F1', 1);
INSERT INTO `04_lista_status` (status, ordem, cor, ativo) VALUES ('Cancelado', 12, '#6B7280', 1);

-- Verify
SELECT * FROM `04_lista_status` ORDER BY ordem;

